-- friction_nodes: 5
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('balkan_theater','Western Balkans political contest','Politischer Wettstreit im Westbalkan','Serbia''s ruling party faces sustained protests after the fatal collapse of a renovated railway canopy in Novi Sad exposed years of unaccountable construction contracting, while Belgrade balances Western pressure over sanctions and energy assets against its ties to Moscow and Beijing. Albania''s coastline has become a flashpoint of its own, as a Kushner-linked resort development draws mass protests, environmental warnings and scrutiny from Brussels even as the government defends the investment as a driver of growth. Together they trace a recurring regional pattern: political elites courting foreign capital and foreign patrons while facing domestic demands for accountability.','Serbiens Regierungspartei sieht sich anhaltenden Protesten ausgesetzt, nachdem der toedliche Einsturz eines renovierten Bahnhofsvordachs in Novi Sad jahrelange unkontrollierte Bauvergabe offenlegte, waehrend Belgrad westlichen Druck wegen Sanktionen und Energieanlagen gegen seine Beziehungen zu Moskau und Peking abwaegt. Albaniens Kueste ist zu einem eigenen Brennpunkt geworden, seit ein mit Kushner verbundenes Resortprojekt Massenproteste, Umweltwarnungen und die Pruefung durch Bruessel auf sich zieht, waehrend die Regierung die Investition als Wachstumstreiber verteidigt. Gemeinsam zeichnen beide Faelle ein wiederkehrendes regionales Muster: politische Eliten, die auslaendisches Kapital und auslaendische Schutzmaechte umwerben, waehrend sie innenpolitisch mit Forderungen nach Rechenschaft konfrontiert sind.',ARRAY['EUROPE-BALKANS'],true,11,'Coverage in mid-2026 centers on Serbia''s protest movement, sustained by demands for Vucic''s resignation and early elections since the fatal Novi Sad canopy collapse, alongside the government''s parallel resistance to Western pressure over Russian-owned energy assets. In Albania, a Trump-family-linked resort project on a protected coastline has drawn weeks of demonstrations, arrests and EU accession warnings, met by the government''s public defense of the deal as economic opportunity. Both episodes foreground the same underlying question across the region: whether ruling parties answer to their publics or to the capital, foreign and domestic, that sustains them.','Die Berichterstattung Mitte 2026 konzentriert sich auf Serbiens Protestbewegung, getragen von Forderungen nach Vucics Ruecktritt und vorgezogenen Neuwahlen seit dem toedlichen Einsturz des Vordachs von Novi Sad, neben dem parallelen Widerstand der Regierung gegen westlichen Druck wegen russischer Energieanlagen. In Albanien haben ein mit der Trump-Familie verbundenes Resortprojekt an einer geschuetzten Kueste wochenlange Demonstrationen, Festnahmen und Warnungen zum EU-Beitritt ausgeloest, denen die Regierung mit einer oeffentlichen Verteidigung des Geschaefts als wirtschaftliche Chance begegnet. Beide Episoden werfen in der Region dieselbe grundlegende Frage auf: ob Regierungsparteien ihrer Oeffentlichkeit Rechenschaft schulden oder dem Kapital, auslaendisch wie inlaendisch, das sie stuetzt.','theater',ARRAY['serbia_government_legitimacy','balkan_foreign_capital'],'{}','regional','{"type": "Point", "coordinates": [20.9, 42.9]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('balkan_foreign_capital','Foreign capital and sovereignty','Auslandskapital und Souveränität','Foreign-backed development projects testing where Western Balkan governments draw the line between welcome investment and the sale of sovereign and environmental interests. The clearest case is a Kushner-linked luxury resort on Albania''s Sazan island, which has drawn sustained protests, environmental warnings over a protected coastline, and scrutiny from Brussels over its implications for EU accession, even as the government defends the deal as a source of jobs and growth.','Auslaendisch finanzierte Entwicklungsprojekte stellen die Frage, wo Regierungen des Westbalkans die Grenze zwischen willkommener Investition und dem Verkauf souveraener und oekologischer Interessen ziehen. Der deutlichste Fall ist ein mit Kushner verbundenes Luxusresort auf der albanischen Insel Sazan, das anhaltende Proteste, Umweltwarnungen wegen einer geschuetzten Kueste und die Pruefung durch Bruessel im Hinblick auf den EU-Beitrittsprozess ausgeloest hat, waehrend die Regierung das Geschaeft als Quelle fuer Arbeitsplaetze und Wachstum verteidigt.',ARRAY['EUROPE-BALKANS'],true,2,'Weeks of protest in Tirana over the Kushner-backed Sazan resort have combined environmental objections -- construction on a protected wetland and coastline -- with warnings that the deal jeopardizes Albania''s EU accession credibility, against a government that has publicly defended the project and characterized opposition to it as politically motivated.','Wochenlange Proteste in Tirana gegen das von Kushner unterstuetzte Sazan-Resort verbinden Umwelteinwaende -- Bauarbeiten auf einem geschuetzten Feuchtgebiet und Kuestenabschnitt -- mit Warnungen, das Geschaeft gefaehrde Albaniens Glaubwuerdigkeit im EU-Beitrittsprozess, gegenueber einer Regierung, die das Projekt oeffentlich verteidigt und den Widerstand dagegen als politisch motiviert bezeichnet hat.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
