  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('serbia_government_legitimacy','Serbia''s contested government','Serbiens umstrittene Regierung','Serbia''s ruling party under sustained pressure since the fatal collapse of a renovated railway station canopy in Novi Sad, which student-led protesters read as proof of systemic corruption in public contracting. Demonstrations demanding resignation and early elections continue alongside the government''s separate resistance to Western pressure over sanctioning Russia and divesting its stake in the Russian-owned oil company NIS.','Serbiens Regierungspartei steht seit dem toedlichen Einsturz eines renovierten Bahnhofsvordachs in Novi Sad unter anhaltendem Druck, den von Studierenden angefuehrte Protestierende als Beweis systemischer Korruption bei der oeffentlichen Auftragsvergabe werten. Die Demonstrationen mit Forderungen nach Ruecktritt und vorgezogenen Neuwahlen dauern an, parallel zum eigenstaendigen Widerstand der Regierung gegen westlichen Druck, Russland zu sanktionieren und ihren Anteil am russischen Oelkonzern NIS zu veraeussern.',ARRAY['EUROPE-BALKANS'],true,1,'Sustained protests since the Novi Sad canopy collapse have put Serbia''s presidency under its most serious domestic challenge in years, with resignation calls, snap-election demands and periodic police crackdowns running alongside a separate track: Vucic''s continued refusal to sanction Russia and his defense of NIS''s US sanctions licence.','Anhaltende Proteste seit dem Einsturz des Vordachs von Novi Sad stellen Serbiens Praesidentschaft vor die ernsteste innenpolitische Herausforderung seit Jahren, mit Ruecktrittsforderungen, Forderungen nach vorgezogenen Neuwahlen und wiederkehrenden Polizeieinsaetzen -- parallel zu einem zweiten Strang: Vucics anhaltender Weigerung, Russland zu sanktionieren, und seiner Verteidigung der US-Sanktionslizenz fuer NIS.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
