-- narratives_v2: 7
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('balkan_investment_development','Foreign investment brings jobs, tourism and international partnership to the Western Balkans','Auslandsinvestitionen bringen Arbeitsplaetze, Tourismus und internationale Partnerschaften auf den Westbalkan','In this framing, carried by the same international wire outlets that report the controversy plus regional business press, foreign capital projects such as the Kushner-backed Sazan resort and Fincantieri''s shipbuilding partnership with Albania represent legitimate economic development that governments defend against what they characterize as politically motivated obstruction. Prime Minister Rama has publicly defended the resort project and framed opposition to it as external interference, insisting investment will proceed.','In dieser von denselben internationalen Nachrichtenagenturen, die auch ueber die Kontroverse berichten, sowie von der regionalen Wirtschaftspresse getragenen Deutung stellen auslaendische Kapitalprojekte wie das von Kushner unterstuetzte Sazan-Resort und die Schiffbau-Partnerschaft von Fincantieri mit Albanien eine legitime wirtschaftliche Entwicklung dar, die Regierungen gegen das verteidigen, was sie als politisch motivierte Blockade bezeichnen. Ministerpraesident Rama hat das Resortprojekt oeffentlich verteidigt und den Widerstand dagegen als aeussere Einmischung eingeordnet und auf einer Fortsetzung der Investition bestanden.',ARRAY['EUROPE-BALKANS','AMERICAS-USA','EUROPE-SOUTH'],ARRAY['vows','push on','defends','backs','hybrid war','won''t stop','denounces violence','shipbuilding','training partnership','memorandum of understanding','wirtschaftliche Chance','Investitionspartnerschaft'],true,ARRAY['Reuters','Bloomberg','Euronews','eKathimerini','ANSA','Albanian Daily News','EurActiv','Associated Press','BBC World','CNN','Deutsche Welle','Financial Times','France 24 (EN)','NPR','Sky News','Corriere della Sera','Der Spiegel','Die Zeit','Al Jazeera','The Guardian','Al-Ahram','El Mundo','Folha de S.Paulo','Haaretz','Helsinki Times','La Nación','MSNBC','News24','Novinite','The Australian','The Hindu','Times of Israel','WION'],'balkan_foreign_capital',1,'Investment as opportunity','Investition als Chance',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('balkan_sovereignty_environmental_rejection','''Albania is not for sale'': a protected coastline is being privatised for elite foreign gain','„Albanien ist nicht zu verkaufen“: eine geschützte Küste wird für den Gewinn einer ausländischen Elite privatisiert','This framing, carried by the same wire outlets under different keywords plus environmental and opposition voices, treats the Kushner-linked resort on the island of Sazan and the Zvernec wetland as a land grab that trades a protected coastline and Albania''s EU accession credibility for the enrichment of a politically connected few. Mass protests, police action against demonstrators and Brussels'' own warnings that the deal risks accession are read as confirmation that the project subverts environmental law and democratic accountability alike.','Diese von denselben Nachrichtenagenturen unter anderen Stichworten sowie von Umwelt- und Oppositionsstimmen getragene Deutung behandelt das mit Kushner verbundene Resort auf der Insel Sazan und das Feuchtgebiet von Zvernec als Landraub, der eine geschuetzte Kueste und Albaniens Glaubwuerdigkeit im EU-Beitrittsprozess fuer die Bereicherung weniger politisch Verbundener opfert. Massenproteste, Polizeieinsaetze gegen Demonstrierende und Bruessels eigene Warnungen, das Geschaeft gefaehrde den Beitrittsprozess, gelten in dieser Lesart als Bestaetigung, dass das Projekt sowohl Umweltrecht als auch demokratische Rechenschaftspflicht untergraebt.',ARRAY['EUROPE-BALKANS','NON-STATE-EU'],ARRAY['not for sale','land grab','protected','wetland','privatising','environmental disaster','outrage','backlash','accession at risk','warns Albania','clashes','arrest protesters','corrupt','protest','rally','demonstrat','anger','controvers','erupt','violent','Proteste','Zusammenstoesse','concern','hurdle','flout','probe'],true,ARRAY['Reuters','Bloomberg','Euronews','eKathimerini','ANSA','Albanian Daily News','EurActiv','Associated Press','BBC World','CNN','Deutsche Welle','Financial Times','France 24 (EN)','NPR','Sky News','Corriere della Sera','Der Spiegel','Die Zeit','Al Jazeera','The Guardian','RT','Press TV','Al-Ahram','El Mundo','Folha de S.Paulo','Haaretz','Helsinki Times','La Nación','MSNBC','News24','Novinite','The Australian','The Hindu','Times of Israel','WION'],'balkan_foreign_capital',2,'Sovereignty & environmental rejection','Souveraenitaets- und Umweltablehnung', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('balkan_theater_external_backing','Russia and China back the region''s governments as they resist Western-aligned pressure','Russland und China unterstuetzen die Regierungen der Region in ihrem Widerstand gegen westlich ausgerichteten Druck','Russian and Chinese state media portray Western and EU pressure on Balkan governments -- whether over sanctions, energy assets or scrutiny of foreign investment deals -- as unwarranted interference in sovereign decision-making, and frame continuity in each government''s own foreign-policy choices as the more stable path.','Russische und chinesische Staatsmedien stellen westlichen und EU-Druck auf die Regierungen des Westbalkans -- ob wegen Sanktionen, Energieanlagen oder der Pruefung auslaendischer Investitionsvorhaben -- als unberechtigte Einmischung in souveraene Entscheidungen dar und werten die Kontinuitaet der aussenpolitischen Entscheidungen der jeweiligen Regierung als den stabileren Weg.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],'{}',true,ARRAY['TASS','TASS (EN)','RT','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','RIA Novosti','CGTN','China Daily'],'balkan_theater',1,'External backing against Western pressure','Externe Rueckendeckung gegen westlichen Druck',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('balkan_theater_investment_opportunity','Foreign capital and international partnerships are framed as development opportunities governments are right to defend','Auslaendisches Kapital und internationale Partnerschaften werden als Entwicklungschancen dargestellt, die Regierungen zu Recht verteidigen','International wire coverage and regional business press present foreign investment projects, from shipbuilding partnerships to large resort developments, as legitimate economic opportunity, reporting governments'' own defense of the deals against domestic and EU objections as a reasonable stance rather than as complicity.','Internationale Agenturberichterstattung und die regionale Wirtschaftspresse stellen auslaendische Investitionsprojekte, von Schiffbau-Partnerschaften bis zu grossen Resortentwicklungen, als legitime wirtschaftliche Chance dar und berichten ueber die eigene Verteidigung der Geschaefte durch die Regierungen gegen innenpolitische und EU-Einwaende als vertretbare Haltung und nicht als Mittaeterschaft.',ARRAY['EUROPE-BALKANS','AMERICAS-USA','EUROPE-SOUTH'],'{}',true,ARRAY['Reuters','Bloomberg','Euronews','eKathimerini','ANSA','Albanian Daily News','EurActiv','Associated Press','BBC World','CNN','Deutsche Welle','Financial Times','France 24 (EN)','NPR','Sky News','Corriere della Sera','Der Spiegel','Die Zeit'],'balkan_theater',2,'Investment as opportunity','Investition als Chance',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('balkan_theater_accountability_deficit','From a collapsed canopy to a privatised coastline, political elites are accused of prioritising power and profit over the public','Vom eingestürzten Vordach bis zur privatisierten Küste: politischen Eliten wird vorgeworfen, Macht und Profit über das Gemeinwohl zu stellen','Independent regional outlets and Western mainstream press link Serbia''s protest movement, ignited by the fatal Novi Sad canopy collapse, with Albania''s Kushner-linked resort controversy as two faces of the same pattern: governing parties accused of shielding corrupt contracting, unaccountable land deals and politically connected beneficiaries from scrutiny, while demonstrators demand resignations, snap elections and legal accountability.','Unabhaengige regionale Medien und die westliche Mainstream-Presse verbinden Serbiens durch den toedlichen Einsturz des Vordachs von Novi Sad ausgeloeste Protestbewegung mit der Kontroverse um das Kushner-verbundene Resort in Albanien als zwei Auspraegungen desselben Musters: Regierungsparteien wird vorgeworfen, korrupte Vergabepraxis, unkontrollierte Landgeschaefte und politisch vernetzte Nutzniesser vor Kontrolle zu schuetzen, waehrend Demonstrierende Ruecktritte, Neuwahlen und rechtliche Rechenschaft fordern.',ARRAY['EUROPE-BALKANS','NON-STATE-EU'],'{}',true,ARRAY['N1 Serbia','Vijesti','N1','Reuters','The Guardian','Der Spiegel','Die Zeit','Der Standard','Tagesschau','Bloomberg','Al Jazeera','Euronews','Kurier','Novinite','Jerusalem Post','Daily Sabah','CNN','eKathimerini','ANSA','Albanian Daily News','EurActiv','Associated Press','BBC World','Deutsche Welle','Financial Times','France 24 (EN)','NPR','Sky News','Corriere della Sera'],'balkan_theater',3,'Elite capture and accountability deficit','Elitenbereicherung und Rechenschaftsdefizit', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('serbia_sovereignty_defense','Belgrade''s resistance to Western pressure defends Serbia''s sovereign right to choose its own path','Belgrads Widerstand gegen westlichen Druck verteidigt Serbiens souveränes Recht auf einen eigenen Kurs','This framing, carried by Russian and Chinese state media, holds that Vucic''s refusal to sanction Russia, his defense of NIS against forced divestment, and his balancing between Brussels, Moscow and Beijing reflect a legitimate multi-vector foreign policy rather than defiance. Domestic protests are read as encouraged or exploited by outside actors seeking to force Serbia into an alignment it has not chosen, and continuity in Belgrade is presented as the safer course for the country''s energy security and independence.','Diese von russischen und chinesischen Staatsmedien getragene Deutung sieht in Vucics Weigerung, Russland zu sanktionieren, seiner Verteidigung von NIS gegen eine erzwungene Veraeusserung und seinem Balancieren zwischen Bruessel, Moskau und Peking eine legitime multivektorale Aussenpolitik und keinen Trotz. Die innenpolitischen Proteste werden als von aussen ermutigt oder ausgenutzt gedeutet, mit dem Ziel, Serbien zu einer nicht gewaehlten Ausrichtung zu zwingen; Kontinuitaet in Belgrad gilt in dieser Lesart als der sicherere Kurs fuer Energiesicherheit und Unabhaengigkeit des Landes.',ARRAY['EUROPE-BALKANS','EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['sovereign','sovereignty','won''t bow','resist pressure','independent course','multi-vector','national interest','energy security','refuses to sanction','wird keine Sanktionen','суверенит','энергетическая безопасность','не введет санкции'],true,ARRAY['TASS','TASS (EN)','RT','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','RIA Novosti','CGTN','China Daily'],'serbia_government_legitimacy',1,'Sovereignty defense','Verteidigung der Souveraenitaet',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('serbia_protest_accountability','Systemic corruption and negligence behind the Novi Sad canopy collapse demand Vucic''s resignation','Systemische Korruption und Fahrlaessigkeit hinter dem Einsturz des Vordachs von Novi Sad verlangen den Ruecktritt Vucics','Carried by Serbia''s independent outlets and Western mainstream press, this framing holds that the fatal collapse of a renovated railway station canopy in Novi Sad exposed years of corrupt, unaccountable construction contracting under SNS rule. Student-led protests demanding justice, snap elections and Vucic''s resignation have met police crackdowns and pressure on public employees, read as further evidence of a government defending itself rather than reforming.','Diese von unabhaengigen serbischen Medien und der westlichen Mainstream-Presse getragene Deutung sieht im toedlichen Einsturz eines renovierten Bahnhofsvordachs in Novi Sad den Beweis jahrelanger korrupter, unkontrollierter Bauvergabe unter der SNS-Herrschaft. Die von Studierenden angefuehrten Proteste, die Gerechtigkeit, vorgezogene Neuwahlen und Vucics Ruecktritt fordern, wurden mit Polizeieinsaetzen und Druck auf oeffentlich Bedienstete beantwortet -- fuer diese Lesart ein weiterer Beleg dafuer, dass sich die Regierung verteidigt, statt zu reformieren.',ARRAY['EUROPE-BALKANS','NON-STATE-EU'],ARRAY['resign','resignation','snap election','accountability','cover-up','negligence','crackdown','tear gas','corruption','impunity','Ruecktritt','Neuwahlen','ostavk','odgovornost','protest','prosvjed','demonstrac','student','izbor','blokad','blockade','nadstrešnic','canopy','Novi Sad'],true,ARRAY['N1 Serbia','Vijesti','N1','Reuters','The Guardian','Der Spiegel','Die Zeit','Der Standard','Tagesschau','Bloomberg','Al Jazeera','Euronews','Kurier','Novinite','Jerusalem Post','Daily Sabah','CNN'],'serbia_government_legitimacy',2,'Accountability protests','Rechenschaftsproteste', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();

COMMIT;
